"use client";
import Link from "next/link";
import { Product, cartApi, wishlistApi } from "@/lib/api";
import { useState } from "react";
export default function ProductCard({ product }: { product: Product }) { const [note, setNote] = useState(""); const addToCart = async () => { try { await cartApi.add(product._id, 1); setNote("Added to cart"); } catch (e:any) { setNote(e.message || "Login required"); } }; const toggleWish = async () => { try { const res = await wishlistApi.toggle(product._id); setNote(res.action === "added" ? "Added to wishlist" : "Removed from wishlist"); } catch (e:any) { setNote(e.message || "Action failed"); } }; return <div className="card card-pad"><div className="product-image">🌿</div><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 14 }}><span className="badge">{product.category}</span><span className="muted" style={{ fontSize: 12, textTransform: "capitalize" }}>{product.sellerRole}</span></div><h3 className="title-md" style={{ marginTop: 14 }}>{product.name}</h3><p className="muted">{product.city || "No city"} • {product.sellerName || "Seller"}</p><p style={{ minHeight: 42 }}>{product.description?.slice(0, 90) || "Fresh quality product available for direct purchase."}</p><strong>Rs {product.price} / {product.unit}</strong><div style={{ display: "flex", gap: 10, marginTop: 14, flexWrap: "wrap" }}><Link href={`/product/${product.slug}`} className="btn btn-secondary">View details</Link><button className="btn btn-primary" onClick={addToCart}>Add to cart</button><button className="btn btn-secondary" onClick={toggleWish}>Wishlist</button></div>{note && <div className="muted" style={{ marginTop: 10 }}>{note}</div>}</div>; }
