"use client"; import { useEffect, useState } from "react"; import PageHeader from "@/components/PageHeader"; import FilterBar from "@/components/FilterBar"; import ProductCard from "@/components/ProductCard"; import { productApi, Product } from "@/lib/api"; export default function MarketplacePage() { const [products, setProducts] = useState<Product[]>([]); const [search, setSearch] = useState(""); const [category, setCategory] = useState(""); const [city, setCity] = useState(""); const [sellerType, setSellerType] = useState(""); const [loading, setLoading] = useState(true); useEffect(() => { setLoading(true); productApi.list({ search, category, city, sellerType }).then((res) => setProducts(res.products)).finally(() => setLoading(false)); }, [search, category, city, sellerType]); return <><PageHeader title="Marketplace" text="Search, filter, and explore products from farmers, restaurants, and industrial users." /><section className="section"><div className="container"><FilterBar search={search} setSearch={setSearch} category={category} setCategory={setCategory} city={city} setCity={setCity} sellerType={sellerType} setSellerType={setSellerType} />{loading ? <div className="empty">Loading marketplace...</div> : products.length === 0 ? <div className="empty">No products found.</div> : <div className="grid grid-3">{products.map((p) => <ProductCard key={p._id} product={p} />)}</div>}</div></section></>; }
