"use client";
const categories = ["", "Vegetables", "Fruits", "Grains", "Dairy", "Flowers", "Seeds", "Processed", "Prepared Food", "Other"];
export default function FilterBar({ search, setSearch, category, setCategory, city, setCity, sellerType, setSellerType }:{ search:string; setSearch:(v:string)=>void; category:string; setCategory:(v:string)=>void; city:string; setCity:(v:string)=>void; sellerType:string; setSellerType:(v:string)=>void; }) { return <div className="card card-pad" style={{ marginBottom: 18 }}><div className="form-grid"><input className="input" value={search} onChange={(e)=>setSearch(e.target.value)} placeholder="Search by product, seller, category" /><select className="select" value={category} onChange={(e)=>setCategory(e.target.value)}>{categories.map(c => <option key={c} value={c}>{c || "All categories"}</option>)}</select><input className="input" value={city} onChange={(e)=>setCity(e.target.value)} placeholder="City" /><select className="select" value={sellerType} onChange={(e)=>setSellerType(e.target.value)}><option value="">All seller types</option><option value="farmer">Farmer</option><option value="restaurant">Restaurant</option><option value="industrial">Industrial</option></select></div></div>; }
